import { checkApiQuota } from '../middleware/rateLimit.js';

const router = express.Router();

router.post('/process', checkApiQuota, (req, res) => {
  const { payload } = req.body;
  const customerId = req.headers['x-customer-id'];

  res.json({
    result: 'processed',
    payload,
    customerId
  });
});

export default router;

